// Last updated 04/2019; G8 added per business change.
export const GRADE_RATES: ReadonlyArray<{code: string; ratePence: number}> = [
  { code: 'G1', ratePence: 984 },   // line 69: 'G1 984' -> 9.84
  { code: 'G2', ratePence: 1075 },  // line 70: 'G21075' -> 10.75
  { code: 'G3', ratePence: 1190 },  // line 71: 'G31190' -> 11.90
  { code: 'G4', ratePence: 1320 },  // line 72: 'G41320' -> 13.20
  { code: 'G5', ratePence: 1475 },  // line 73: 'G51475' -> 14.75
  { code: 'G6', ratePence: 1710 },  // line 74: 'G61710' -> 17.10
  { code: 'G7', ratePence: 1995 },  // line 75: 'G71995' -> 19.95
