import { GRADE_RATES } from './gradeRates';

/**
 * Returns the hourly rate in pence for the given grade code.
 * Searches the GRADE_RATES array (first match) – matches original PERFORM VARYING loop.
 * @returns rate in pence, or undefined if grade not found (COBOL leaves WS-BASE-RATE unchanged).
 */
export function getHourlyRatePence(gradeCode: string): number | undefined {
  for (const entry of GRADE_RATES) {
    if (entry.code === gradeCode) {
      return entry.ratePence;
    }
  }
  return undefined;
}

